import{a2 as s,a3 as a,ao as p}from"./index.37c25fac.js";var t="/posts/5-1.png",o="/posts/5-regex.png",c="/posts/5-diff.png";const e={class:"md-blog m-auto text-left"},u=p('<h1 id="csapp-%E4%B9%8B-shell-lab" tabindex="-1">CSAPP \u4E4B Shell Lab</h1><p>\u535A\u5BA2\u6458\u51E0\u7BC7\u81EA\u5DF1\u505A\u7684 CSAPP \u53D1\u53D1\uFF08\u81EA\u8BA4\u4E3A\u53EF\u80FD\u6709\u70B9\u53C2\u8003\u4EF7\u503C\uFF09</p><p>\u5168\u90E8\u4EE3\u7801\u53EF\u4EE5\u89C1 <a href="https://github.com/liuly0322/CSAPP-LABS">github \u4ED3\u5E93</a></p><p>\u672C\u7BC7\u662F Shell Lab</p><p>\u672C\u6B21\u5B9E\u9A8C\u7684\u8981\u6C42\u662F\u5B9E\u73B0\u4E00\u4E2A\u652F\u6301\u4EFB\u52A1\u63A7\u5236\u7684 Unix shell \u7A0B\u5E8F</p><p>\u7A0B\u5E8F\u7684\u6846\u67B6\u5DF2\u7ECF\u7ED9\u51FA\uFF0C\u53EA\u9700\u8981\u8865\u5145\u4E00\u4E9B\u529F\u80FD\u6027\u7684\u51FD\u6570</p><p>\u7531\u4E8E\u6574\u4F53\u662F\u4E00\u4E2A\u7F16\u7A0B\u6027\u8D28\u7684\u5B9E\u9A8C\uFF0C\u6240\u4EE5\u8FD9\u91CC\u53EA\u5728\u8D34\u4E0A\u6700\u540E\u7ED3\u679C\u540E\uFF0C\u8BB2\u4E00\u4E9B\u5B9E\u9A8C\u4E2D\u503C\u5F97\u6CE8\u610F\u7684\u51FD\u6570</p><h2 id="%E8%AF%84%E6%B5%8B" tabindex="-1">\u8BC4\u6D4B</h2><p>\u53EF\u80FD\u7531\u4E8E\u6BCF\u6B21\u8FD0\u884C\u7684 pid \u90FD\u6709\u6240\u4E0D\u540C\uFF0C\u5E76\u4E14\u4E5F\u65E0\u6CD5\u4FDD\u8BC1 <code>/bin/ps</code> \u884C\u4E3A\u76F8\u540C\uFF0C\u672C\u5B9E\u9A8C\u6CA1\u6709\u7ED9\u51FA\u4E00\u952E\u6D4B\u8BD5 shell \u6B63\u786E\u6027\u7684\u7A0B\u5E8F</p><p>\u4F46\u5BF9\u4E8E\u6BCF\u4E2A\u8BC4\u6D4B\u70B9\uFF0C\u90FD\u7ED9\u51FA\u4E86 <code>tsh</code> \u548C <code>tshref</code> \u751F\u6210\u8FD0\u884C\u7ED3\u679C\u7684\u7A0B\u5E8F</p><p>\u6240\u4EE5\u53EA\u8981\u6279\u91CF\u751F\u6210\u7ED3\u679C\u540E\u624B\u52A8\u6BD4\u8F83\u5373\u53EF</p><p><code>tshref</code> \u7684\u7ED3\u679C\u5DF2\u7ECF\u7ED9\u51FA\uFF0C\u5728 <code>tshref.out</code> \u6587\u4EF6\u4E2D\uFF0C\u4E0B\u9762\u6211\u4EEC\u5199\u4E00\u4E2A\u811A\u672C\u6279\u91CF\u751F\u6210 <code>tsh</code> \u7684\u8FD0\u884C\u7ED3\u679C (fish \u811A\u672C\uFF0C\u8BED\u6CD5\u4E0E posix \u6709\u6240\u4E0D\u540C)</p><p><img src="'+t+'" alt=""></p><p>\u7136\u540E\u624B\u52A8\u6BD4\u8F83\u6587\u4EF6</p><p>\uFF08\u56E0\u4E3A pid \u90FD\u5728\u62EC\u53F7\u5185\uFF0C\u6240\u4EE5\u9996\u5148\u7528\u6B63\u5219\u8868\u8FBE\u5F0F\u628A pid \u7EDF\u4E00\u66FF\u6362\u6210 10000\uFF09</p><p><img src="'+o+`" alt=""></p><p>\u968F\u540E\u6BD4\u8F83\uFF1A</p><pre class="language-bash"><code class="language-bash"><span class="token function">diff</span> <span class="token number">1</span>.out tshref.out <span class="token operator">&gt;</span> out.diff
</code></pre><p>\u67E5\u770B\u53D1\u73B0\u53EA\u6709 <code>ps</code> \u8FD0\u884C\u7ED3\u679C\u4E0D\u540C\uFF0C\u800C\u8FD0\u884C\u884C\u4E3A\u8FBE\u5230\u9884\u671F</p><p><img src="`+c+`" alt=""></p><p>\u56E0\u6B64\u5B9E\u9A8C\u5B8C\u6210</p><h2 id="eval" tabindex="-1">eval</h2><p>\u8865\u5168\u5982\u4E0B\uFF1A</p><pre class="language-cpp"><code class="language-cpp"><span class="token keyword">void</span> <span class="token function">eval</span><span class="token punctuation">(</span><span class="token keyword">char</span><span class="token operator">*</span> cmdline<span class="token punctuation">)</span> <span class="token punctuation">{</span>
    <span class="token keyword">char</span><span class="token operator">*</span> argv<span class="token punctuation">[</span>MAXARGS<span class="token punctuation">]</span><span class="token punctuation">;</span>
    <span class="token keyword">int</span> bg<span class="token punctuation">;</span>
    pid_t pid<span class="token punctuation">;</span>

    bg <span class="token operator">=</span> <span class="token function">parseline</span><span class="token punctuation">(</span>cmdline<span class="token punctuation">,</span> argv<span class="token punctuation">)</span><span class="token punctuation">;</span>
    <span class="token keyword">if</span> <span class="token punctuation">(</span>argv<span class="token punctuation">[</span><span class="token number">0</span><span class="token punctuation">]</span> <span class="token operator">==</span> <span class="token constant">NULL</span><span class="token punctuation">)</span>
        <span class="token keyword">return</span><span class="token punctuation">;</span>

    <span class="token keyword">if</span> <span class="token punctuation">(</span><span class="token operator">!</span><span class="token function">builtin_cmd</span><span class="token punctuation">(</span>argv<span class="token punctuation">)</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
        <span class="token keyword">if</span> <span class="token punctuation">(</span><span class="token punctuation">(</span>pid <span class="token operator">=</span> <span class="token function">fork</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span> <span class="token operator">==</span> <span class="token number">0</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
            <span class="token function">setpgid</span><span class="token punctuation">(</span><span class="token number">0</span><span class="token punctuation">,</span> <span class="token number">0</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
            <span class="token keyword">if</span> <span class="token punctuation">(</span><span class="token function">execve</span><span class="token punctuation">(</span>argv<span class="token punctuation">[</span><span class="token number">0</span><span class="token punctuation">]</span><span class="token punctuation">,</span> argv<span class="token punctuation">,</span> environ<span class="token punctuation">)</span> <span class="token operator">&lt;</span> <span class="token number">0</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
                <span class="token function">printf</span><span class="token punctuation">(</span><span class="token string">&quot;%s: Command not found\\n&quot;</span><span class="token punctuation">,</span> argv<span class="token punctuation">[</span><span class="token number">0</span><span class="token punctuation">]</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
                <span class="token function">exit</span><span class="token punctuation">(</span><span class="token number">0</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
            <span class="token punctuation">}</span>
        <span class="token punctuation">}</span>

        <span class="token comment">// \u6B64\u5904\u662F\u7236\u8FDB\u7A0B</span>
        <span class="token function">addjob</span><span class="token punctuation">(</span>jobs<span class="token punctuation">,</span> pid<span class="token punctuation">,</span> <span class="token punctuation">(</span>bg <span class="token operator">==</span> <span class="token number">1</span> <span class="token operator">?</span> BG <span class="token operator">:</span> FG<span class="token punctuation">)</span><span class="token punctuation">,</span> cmdline<span class="token punctuation">)</span><span class="token punctuation">;</span>
        <span class="token keyword">if</span> <span class="token punctuation">(</span><span class="token operator">!</span>bg<span class="token punctuation">)</span> <span class="token punctuation">{</span>
            <span class="token function">waitfg</span><span class="token punctuation">(</span>pid<span class="token punctuation">)</span><span class="token punctuation">;</span>
        <span class="token punctuation">}</span> <span class="token keyword">else</span> <span class="token punctuation">{</span>
            <span class="token function">printf</span><span class="token punctuation">(</span><span class="token string">&quot;[%d] (%d) %s&quot;</span><span class="token punctuation">,</span> <span class="token function">pid2jid</span><span class="token punctuation">(</span>pid<span class="token punctuation">)</span><span class="token punctuation">,</span> pid<span class="token punctuation">,</span> cmdline<span class="token punctuation">)</span><span class="token punctuation">;</span>
        <span class="token punctuation">}</span>
    <span class="token punctuation">}</span>

    <span class="token keyword">return</span><span class="token punctuation">;</span>
<span class="token punctuation">}</span>
</code></pre><p>\u548C\u4E66\u4E0A\u7ED9\u51FA\u7684\u4F8B\u7A0B\u5DEE\u4E0D\u591A\uFF0C\u4E3B\u8981\u533A\u522B\u5982\u4E0B\uFF1A</p><ul><li><code>setpgid(0, 0);</code> \u4F7F\u5F97\u80FD\u6B63\u5E38\u63A5\u53D7\u522B\u7684 <code>shell</code> \u53D1\u9001\u7684\u7EC8\u6B62\u4FE1\u53F7\uFF0C\u5426\u5219\u81EA\u5DF1\u7684\u6240\u6709\u5B50\u8FDB\u7A0B\u90FD\u4F1A\u88AB\u7EC8\u6B62</li><li>\u524D\u53F0\u8FDB\u7A0B\u7684\u963B\u585E\u7528\u7684\u662F <code>waitfg</code>\uFF0C\u540E\u9762\u5B9E\u73B0 <code>fg</code> \u547D\u4EE4\u4E5F\u9700\u8981\u7528\u5230\u8FD9\u4E00\u51FD\u6570</li></ul><p>\u7406\u8BBA\u4E0A\u6765\u8BF4\u8FD9\u91CC\u9700\u8981\u8003\u8651\u5C4F\u853D\u4FE1\u53F7\uFF0C\u5B9E\u9645\u4E0A\uFF0C\u73B0\u4EE3\u8BA1\u7B97\u673A\u591A\u6838 cpu \u5E76\u884C\u8FD0\u884C\u5404\u4E2A\u8FDB\u7A0B\uFF0C\u5728\u8FDB\u7A0B\u6570\u5C0F\u7684\u60C5\u51B5\u4E0B\u5F88\u96BE\u56E0\u4E3A\u5E76\u53D1\u9047\u5230\u6267\u884C\u65F6\u5E8F\u7684\u95EE\u9898\uFF0C\u4E0D\u8FC7\u4E25\u8C28\u8003\u8651\u8FD8\u662F\u52A0\u9501\u4E3A\u597D\uFF0C\u8FD9\u91CC\u4F5C\u4E3A\u4E00\u4E2A toy \u7A0B\u5E8F\u5C31\u6CA1\u52A0\u4E86</p><h2 id="do_bgfg" tabindex="-1">do_bgfg</h2><p>\u8FD9\u91CC\u7684 <code>do_xx</code> \u4F3C\u4E4E\u662F\u8FD9\u79CD\u89E3\u91CA\u5668\u7A0B\u5E8F\u666E\u904D\u7684\u547D\u540D\u4E60\u60EF\uFF0C\u4EE3\u8868\u6267\u884C\u4EC0\u4E48\u4EC0\u4E48\u5185\u7F6E\u6307\u4EE4</p><p><code>bg</code> \u548C <code>fg</code> \u8981\u5B9E\u73B0\u7684\u662F\u5BF9\u8FDB\u7A0B\u8FD0\u884C\u72B6\u6001\u7684\u8F6C\u6362</p><pre class="language-cpp"><code class="language-cpp"><span class="token keyword">void</span> <span class="token function">do_bgfg</span><span class="token punctuation">(</span><span class="token keyword">char</span><span class="token operator">*</span><span class="token operator">*</span> argv<span class="token punctuation">)</span> <span class="token punctuation">{</span>
    <span class="token keyword">int</span> id<span class="token punctuation">;</span>
    <span class="token keyword">struct</span> <span class="token class-name">job_t</span><span class="token operator">*</span> job<span class="token punctuation">;</span>

    <span class="token comment">// \u8FD9\u91CC\u6839\u636E\u53C2\u6570\u5224\u65AD\u5408\u6CD5\u6027\uFF0C\u83B7\u53D6 job</span>
    <span class="token punctuation">.</span><span class="token punctuation">.</span><span class="token punctuation">.</span><span class="token punctuation">.</span><span class="token punctuation">.</span><span class="token punctuation">.</span>

    job<span class="token operator">-&gt;</span>state <span class="token operator">=</span> <span class="token punctuation">(</span>argv<span class="token punctuation">[</span><span class="token number">0</span><span class="token punctuation">]</span><span class="token punctuation">[</span><span class="token number">0</span><span class="token punctuation">]</span> <span class="token operator">==</span> <span class="token char">&#39;b&#39;</span> <span class="token operator">?</span> BG <span class="token operator">:</span> FG<span class="token punctuation">)</span><span class="token punctuation">;</span>
    <span class="token function">kill</span><span class="token punctuation">(</span><span class="token operator">-</span>job<span class="token operator">-&gt;</span>pid<span class="token punctuation">,</span> SIGCONT<span class="token punctuation">)</span><span class="token punctuation">;</span>
    <span class="token keyword">if</span> <span class="token punctuation">(</span>argv<span class="token punctuation">[</span><span class="token number">0</span><span class="token punctuation">]</span><span class="token punctuation">[</span><span class="token number">0</span><span class="token punctuation">]</span> <span class="token operator">==</span> <span class="token char">&#39;b&#39;</span><span class="token punctuation">)</span>
        <span class="token function">printf</span><span class="token punctuation">(</span><span class="token string">&quot;[%d] (%d) %s&quot;</span><span class="token punctuation">,</span> job<span class="token operator">-&gt;</span>jid<span class="token punctuation">,</span> job<span class="token operator">-&gt;</span>pid<span class="token punctuation">,</span> job<span class="token operator">-&gt;</span>cmdline<span class="token punctuation">)</span><span class="token punctuation">;</span>
    <span class="token keyword">else</span>
        <span class="token function">waitfg</span><span class="token punctuation">(</span>job<span class="token operator">-&gt;</span>pid<span class="token punctuation">)</span><span class="token punctuation">;</span>

    <span class="token keyword">return</span><span class="token punctuation">;</span>
<span class="token punctuation">}</span>
</code></pre><p>\u6CE8\u610F\u524D\u53F0\u8FDB\u7A0B\u9700\u8981\u7B49\u5F85\u5373\u53EF</p><h2 id="waitfg" tabindex="-1">waitfg</h2><p>\u5F88\u5B9E\u7528\u7684 <code>helper</code> \u51FD\u6570</p><pre class="language-cpp"><code class="language-cpp"><span class="token keyword">void</span> <span class="token function">waitfg</span><span class="token punctuation">(</span>pid_t pid<span class="token punctuation">)</span> <span class="token punctuation">{</span>
    <span class="token keyword">struct</span> <span class="token class-name">job_t</span><span class="token operator">*</span> job <span class="token operator">=</span> <span class="token function">getjobpid</span><span class="token punctuation">(</span>jobs<span class="token punctuation">,</span> pid<span class="token punctuation">)</span><span class="token punctuation">;</span>
    <span class="token keyword">while</span> <span class="token punctuation">(</span>job<span class="token operator">-&gt;</span>state <span class="token operator">==</span> FG<span class="token punctuation">)</span> <span class="token punctuation">{</span>
        <span class="token function">sleep</span><span class="token punctuation">(</span><span class="token number">1</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
    <span class="token punctuation">}</span>
    <span class="token keyword">return</span><span class="token punctuation">;</span>
<span class="token punctuation">}</span>
</code></pre><p>\u6309\u7167\u5B9E\u9A8C\u8BF4\u660E\u7684\u63A8\u8350\uFF0C\u91C7\u7528\u8F6E\u8BE2\u52A0\u4E0A\u4F11\u7720\u7684\u65B9\u5F0F\u5373\u53EF\uFF0C\u8FD9\u6837\u5BF9\u8FD9\u4E00\u8FDB\u7A0B\u7684\u8D1F\u62C5\u4E5F\u6BD4\u8F83\u5C0F</p><h2 id="sigint-%26-sigtstp" tabindex="-1">sigint &amp; sigtstp</h2><p>\u63A5\u4E0B\u6765\u662F\u51E0\u4E2A\u4FE1\u53F7\u5904\u7406\u65F6\u7684\u5F02\u6B65\u56DE\u8C03\u51FD\u6570</p><pre class="language-cpp"><code class="language-cpp"><span class="token keyword">void</span> <span class="token function">sigint_handler</span><span class="token punctuation">(</span><span class="token keyword">int</span> sig<span class="token punctuation">)</span> <span class="token punctuation">{</span>
    pid_t f_pid <span class="token operator">=</span> <span class="token function">fgpid</span><span class="token punctuation">(</span>jobs<span class="token punctuation">)</span><span class="token punctuation">;</span>
    <span class="token keyword">if</span> <span class="token punctuation">(</span>f_pid<span class="token punctuation">)</span> <span class="token punctuation">{</span>
        <span class="token function">kill</span><span class="token punctuation">(</span><span class="token operator">-</span>f_pid<span class="token punctuation">,</span> sig<span class="token punctuation">)</span><span class="token punctuation">;</span>
    <span class="token punctuation">}</span>
    <span class="token keyword">return</span><span class="token punctuation">;</span>
<span class="token punctuation">}</span>
</code></pre><pre class="language-cpp"><code class="language-cpp"><span class="token keyword">void</span> <span class="token function">sigtstp_handler</span><span class="token punctuation">(</span><span class="token keyword">int</span> sig<span class="token punctuation">)</span> <span class="token punctuation">{</span>
    pid_t f_pid <span class="token operator">=</span> <span class="token function">fgpid</span><span class="token punctuation">(</span>jobs<span class="token punctuation">)</span><span class="token punctuation">;</span>
    <span class="token keyword">if</span> <span class="token punctuation">(</span>f_pid<span class="token punctuation">)</span> <span class="token punctuation">{</span>
        <span class="token function">kill</span><span class="token punctuation">(</span><span class="token operator">-</span>f_pid<span class="token punctuation">,</span> sig<span class="token punctuation">)</span><span class="token punctuation">;</span>
    <span class="token punctuation">}</span>
    <span class="token keyword">return</span><span class="token punctuation">;</span>
<span class="token punctuation">}</span>
</code></pre><p>\u8FD9\u4E24\u4E2A\u51FD\u6570\u6BD4\u8F83\u7C7B\u4F3C\uFF0C\u63A5\u6536\u5230\u952E\u76D8\u7684\u7EC8\u6B62 / \u6682\u505C\u4FE1\u53F7\u540E\u53D1\u9001\u7ED9\u524D\u53F0\u8FDB\u7A0B\u7684\u8FDB\u7A0B\u7EC4\uFF0C\u6240\u4EE5\u7528 <code>-f_pid</code></p><h2 id="sigchld" tabindex="-1">sigchld</h2><p>\u8FD9\u4E00\u90E8\u5206\u7528\u4E8E\u5904\u7406\u5B50\u8FDB\u7A0B\u7684\u4E2D\u65AD / \u6682\u505C\u4FE1\u53F7</p><pre class="language-cpp"><code class="language-cpp"><span class="token keyword">void</span> <span class="token function">sigchld_handler</span><span class="token punctuation">(</span><span class="token keyword">int</span> sig<span class="token punctuation">)</span> <span class="token punctuation">{</span>
    pid_t pid<span class="token punctuation">;</span>
    <span class="token keyword">int</span> status<span class="token punctuation">;</span>

    <span class="token keyword">while</span> <span class="token punctuation">(</span><span class="token punctuation">(</span>pid <span class="token operator">=</span> <span class="token function">waitpid</span><span class="token punctuation">(</span><span class="token operator">-</span><span class="token number">1</span><span class="token punctuation">,</span> <span class="token operator">&amp;</span>status<span class="token punctuation">,</span> WNOHANG <span class="token operator">|</span> WUNTRACED<span class="token punctuation">)</span><span class="token punctuation">)</span> <span class="token operator">&gt;</span> <span class="token number">0</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
        <span class="token keyword">if</span> <span class="token punctuation">(</span><span class="token function">WIFSTOPPED</span><span class="token punctuation">(</span>status<span class="token punctuation">)</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>       <span class="token comment">// \u6682\u505C\u4FE1\u53F7</span>
            <span class="token function">printf</span><span class="token punctuation">(</span><span class="token string">&quot;Job [%d] (%d) stopped by signal %d\\n&quot;</span><span class="token punctuation">,</span> <span class="token function">pid2jid</span><span class="token punctuation">(</span>pid<span class="token punctuation">)</span><span class="token punctuation">,</span> pid<span class="token punctuation">,</span>
                   <span class="token function">WSTOPSIG</span><span class="token punctuation">(</span>status<span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
            <span class="token function">getjobpid</span><span class="token punctuation">(</span>jobs<span class="token punctuation">,</span> pid<span class="token punctuation">)</span><span class="token operator">-&gt;</span>state <span class="token operator">=</span> ST<span class="token punctuation">;</span>
        <span class="token punctuation">}</span> <span class="token keyword">else</span> <span class="token punctuation">{</span>
            <span class="token keyword">if</span> <span class="token punctuation">(</span><span class="token function">WIFSIGNALED</span><span class="token punctuation">(</span>status<span class="token punctuation">)</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>  <span class="token comment">// \u9000\u51FA\u4FE1\u53F7</span>
                <span class="token function">printf</span><span class="token punctuation">(</span><span class="token string">&quot;Job [%d] (%d) terminated by signal %d\\n&quot;</span><span class="token punctuation">,</span> <span class="token function">pid2jid</span><span class="token punctuation">(</span>pid<span class="token punctuation">)</span><span class="token punctuation">,</span>
                       pid<span class="token punctuation">,</span> <span class="token function">WTERMSIG</span><span class="token punctuation">(</span>status<span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
            <span class="token punctuation">}</span>
            <span class="token comment">// \u5B50\u8FDB\u7A0B\u9000\u51FA\u4FE1\u53F7\uFF0C\u4EE5\u53CA\u6B63\u5E38\u8FD0\u884C\u7ED3\u675F</span>
            <span class="token function">deletejob</span><span class="token punctuation">(</span>jobs<span class="token punctuation">,</span> pid<span class="token punctuation">)</span><span class="token punctuation">;</span>
        <span class="token punctuation">}</span>
    <span class="token punctuation">}</span>
    <span class="token keyword">return</span><span class="token punctuation">;</span>
<span class="token punctuation">}</span>
</code></pre><p>\u6CE8\u610F\u7531\u4E8E unix \u4FE1\u53F7\u7684\u963B\u585E\u673A\u5236\uFF0C\u8FD9\u91CC\u9700\u8981\u7528 <code>while</code> \u5904\u7406\u6240\u6709\u7684\u50F5\u6B7B\u8FDB\u7A0B</p><h2 id="debug-%E7%BB%86%E8%8A%82" tabindex="-1">debug \u7EC6\u8282</h2><p>\u7531\u4E8E\u662F\u7F16\u7A0B\u5B9E\u9A8C\uFF0C\u8FD9\u4E00\u90E8\u5206\u8BB0\u5F55\u5B9E\u9A8C\u8FC7\u7A0B\u4E2D\u9047\u5230\u7684\u6709\u610F\u601D\u7684\u95EE\u9898\u4EE5\u53CA\u89E3\u51B3\u65B9\u6848</p><h3 id="%E4%BF%A1%E5%8F%B7%E5%A4%84%E7%90%86" tabindex="-1">\u4FE1\u53F7\u5904\u7406</h3><p>\u5728 <code>sigchld_handler</code> \u51FD\u6570\u4E2D\uFF0C\u4E00\u5F00\u59CB\u4EFF\u7167\u4E66\u672C (\u6CE8\uFF1A\u7B2C\u4E8C\u7248\u4E66)\uFF0C\u91C7\u7528\u7684\u6761\u4EF6\u662F</p><pre class="language-cpp"><code class="language-cpp"><span class="token keyword">while</span> <span class="token punctuation">(</span><span class="token punctuation">(</span>pid <span class="token operator">=</span> <span class="token function">waitpid</span><span class="token punctuation">(</span><span class="token operator">-</span><span class="token number">1</span><span class="token punctuation">,</span> <span class="token operator">&amp;</span>status<span class="token punctuation">,</span> <span class="token number">0</span><span class="token punctuation">)</span><span class="token punctuation">)</span> <span class="token operator">&gt;</span> <span class="token number">0</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
    <span class="token punctuation">.</span><span class="token punctuation">.</span><span class="token punctuation">.</span><span class="token punctuation">.</span><span class="token punctuation">.</span><span class="token punctuation">.</span>
<span class="token punctuation">}</span>
</code></pre><p>\u4F46\u662F\u4F1A\u51FA\u73B0\u5947\u602A\u7684 bug\uFF0C\u7EC8\u6B62\u8FDB\u7A0B\u8F93\u51FA\u7684\u63D0\u793A\u5747\u4E3A <code>[0] (0)</code></p><p>\u5B9E\u9645\u4E0A\u4E66\u672C\u7684\u5199\u6CD5\u662F\u6709\u4E9B\u95EE\u9898\u7684\uFF1A\u8FD9\u6837\u505A\u867D\u7136\u4F1A\u56DE\u6536\u6240\u6709\u7684\u50F5\u6B7B\u8FDB\u7A0B\uFF0C\u4F46\u662F <code>waitpid</code> \u7684\u9ED8\u8BA4\u884C\u4E3A\u4F1A\u4E0D\u65AD\u7B49\u5F85\u6D3B\u8DC3\u8FDB\u7A0B\uFF0C\u76F4\u5230\u6D3B\u8DC3\u8FDB\u7A0B\u50F5\u6B7B\u624D\u4F1A\u8FD4\u56DE</p><p>\u800C\u6211\u4EEC\u867D\u7136\u5E0C\u671B\u4FE1\u53F7\u5904\u7406\u51FD\u6570\u80FD\u591F\u56DE\u6536\u6240\u6709\u7684\u8FDB\u7A0B\uFF0C\u4F46\u6211\u4EEC\u4E5F\u4E0D\u5E0C\u671B\u4FE1\u53F7\u5904\u7406\u5904\u7406\u51FD\u6570\u4F1A\u4E00\u76F4\u963B\u585E\uFF0C\u76F4\u5230\u6240\u6709\u8FDB\u7A0B\u8FD0\u884C\u5B8C\u6BD5\u624D\u7EE7\u7EED\u6267\u884C\uFF0C\u8FD9\u6837\u7684\u8BDD\u4E4B\u540E\u8FDE\u524D\u53F0\u8FDB\u7A0B\u90FD\u4E0D\u5B58\u5728\u4E86\uFF0C\u81EA\u7136\u4E5F\u5C31\u83B7\u53D6\u4E0D\u5230\u524D\u53F0\u8FDB\u7A0B\u7684 <code>pid</code> \u4E86\uFF0C\u6545 shell \u7684\u663E\u793A\u5C31\u4F1A\u51FA\u73B0\u95EE\u9898\u3002\u7406\u60F3\u60C5\u51B5\u4E0B\uFF0C\u5E94\u8BE5\u662F\u4E00\u6B21\u4FE1\u53F7\u5904\u7406\u51FD\u6570\u5904\u7406\u5B8C\u5F53\u524D\u6240\u6709\u50F5\u6B7B\u8FDB\u7A0B\u540E\u5C31\u9000\u51FA</p><p>\u6362\u8A00\u4E4B\uFF0C\u8FD9\u91CC\u7684 <code>waitpid</code> \u5E94\u8BE5\u662F\u4E00\u4E2A\u540C\u6B65\u51FD\u6570\u800C\u975E\u5F02\u6B65\u51FD\u6570</p><p>\uFF08\u5410\u69FD\u4E00\u4E0B\uFF0C\u9AD8\u7EA7\u8BED\u8A00\u7684\u540C\u6B65\u5F02\u6B65\u51FD\u6570\u5199\u591A\u4E86\u518D\u770B C \u8BED\u8A00\u8FD9\u79CD\u9762\u5411\u5E95\u5C42\u7684\u8BED\u8A00\u786E\u5B9E\u6709\u70B9\u5C0F\u5934\u75BC\uFF09</p><p>\u4E3A\u4E86\u4FEE\u6B63\u8FD9\u4E00\u95EE\u9898\uFF0C\u53EF\u4EE5\u901A\u8FC7\u8BBE\u7F6E <code>waitpid</code> \u7684 <code>options</code> \u53C2\u6570\u6539\u53D8 <code>waitpid</code> \u7684\u9ED8\u8BA4\u884C\u4E3A</p><p>\u4FEE\u6539\u540E\u5982\u4E0B\uFF1A</p><pre class="language-cpp"><code class="language-cpp"><span class="token keyword">while</span> <span class="token punctuation">(</span><span class="token punctuation">(</span>pid <span class="token operator">=</span> <span class="token function">waitpid</span><span class="token punctuation">(</span><span class="token operator">-</span><span class="token number">1</span><span class="token punctuation">,</span> <span class="token operator">&amp;</span>status<span class="token punctuation">,</span> WNOHANG <span class="token operator">|</span> WUNTRACED<span class="token punctuation">)</span><span class="token punctuation">)</span> <span class="token operator">&gt;</span> <span class="token number">0</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
    <span class="token punctuation">.</span><span class="token punctuation">.</span><span class="token punctuation">.</span><span class="token punctuation">.</span><span class="token punctuation">.</span><span class="token punctuation">.</span>
<span class="token punctuation">}</span>
</code></pre><p><code>WNOHANG</code> \u9009\u9879\u4F7F\u5F97\u8FD9\u4E00\u51FD\u6570\u53D8\u4E3A\u540C\u6B65\u51FD\u6570\uFF0C\u5982\u679C\u6CA1\u6709\u50F5\u6B7B\u8FDB\u7A0B\u5C31\u7ACB\u523B\u8FD4\u56DE</p><p><code>WUNTRACED</code> \u9009\u9879\u4F7F\u5F97\u8FD9\u4E00\u51FD\u6570\u80FD\u591F\u5904\u7406\u6682\u505C\u7684\u8FDB\u7A0B</p><h3 id="printf" tabindex="-1">printf</h3><p>\u53EF\u80FD\u5728\u9605\u8BFB\u4E0A\u9762\u4EE3\u7801\u65F6\uFF0C\u8BFB\u8005\u4F1A\u89C9\u5F97 <code>sigchld_handler</code> \u7684\u4FE1\u53F7\u5904\u7406\u5F88\u4E0D\u4F18\u96C5\uFF0C <code>printf</code> \u8FD9\u79CD\u6839\u636E\u4FE1\u53F7\u7C7B\u578B\u6765\u6253\u5370\u7684\u51FD\u6570\u4E3A\u4EC0\u4E48\u4E0D\u653E\u5728\u5177\u4F53\u7684\u4FE1\u53F7\u5904\u7406\u51FD\u6570\u91CC\uFF0C\u800C\u662F\u9009\u62E9\u653E\u5728\u4E00\u4E2A\u5927\u7684\u56DE\u6536\u5B50\u8FDB\u7A0B\u7684\u51FD\u6570\u5185\u5462\uFF1F</p><p>\u4ECE\u529F\u80FD\u4E0A\u6765\u8BF4\uFF0C\u662F\u56E0\u4E3A\u5982\u679C shell \u4E2D\u8FD0\u884C\u7684\u5B50\u8FDB\u7A0B\u6536\u5230\u7EC8\u6B62 / \u6682\u505C\u4FE1\u53F7\u800C\u7EC8\u6B62\uFF0C\u6211\u4EEC\u5E0C\u671B shell \u7A0B\u5E8F\u4E5F\u80FD\u63D0\u793A\u7528\u6237\u3002\u800C\u4FE1\u53F7\u5904\u7406\u51FD\u6570\u53EA\u80FD\u5904\u7406 shell \u8FDB\u7A0B\u81EA\u8EAB\u6536\u5230\u7684\u4FE1\u53F7\uFF0C\u9002\u7528\u8303\u56F4\u5C31\u7A84\u4E86\u3002\u5982\u679C\u628A\u6253\u5370\u5199\u5728\u4FE1\u53F7\u5904\u7406\u51FD\u6570\u5185\uFF0C\u4FE1\u53F7\u4F9D\u65E7\u4F1A\u5F97\u5230\u5904\u7406\uFF0C\u4F46\u662F\u4F1A\u5728 <code>test16</code> \u4E2D\u56E0\u4E3A\u6CA1\u6709\u5B50\u8FDB\u7A0B\u7EC8\u6B62\u4FE1\u53F7\u7684\u63D0\u793A\uFF0C\u8F93\u51FA\u4E0E <code>tshref</code> \u4E0D\u4E00\u81F4</p><p>\u503C\u5F97\u4E00\u63D0\u7684\u662F\uFF0C\u8FD9\u91CC\u6709\u4E00\u4E2A\u5F88\u6709\u610F\u601D\u7684\u5B89\u5168\u95EE\u9898\uFF0C\u7531\u4FE1\u53F7\u5904\u7406\u51FD\u6570\u4E2D\u7684 <code>printf</code> \u5F15\u53D1\u3002\u6211\u4EEC\u73B0\u5728\u6240\u5199\u7684 <code>sigchld_handler</code> \u4E8B\u5B9E\u4E0A\u4E5F\u662F\u4E0D\u5B89\u5168\u7684\uFF0CC \u8BED\u8A00\u4E2D\u4FE1\u53F7\u5904\u7406\u51FD\u6570\u4E2D\u80FD\u5B89\u5168\u8C03\u7528\u7684\u51FD\u6570\u662F\u6709\u9650\u7684\uFF0C\u53EF\u4EE5\u5728 <a href="https://man7.org/linux/man-pages/man7/signal-safety.7.html">\u8FD9\u4E2A\u7F51\u7AD9</a> \u67E5\u9605</p><p>\u800C <code>printf</code> \u51FD\u6570\u5E76\u4E0D\u5728\u6B64\u5217\uFF0C\u8FD9\u662F\u56E0\u4E3A <code>printf</code> \u4E3A\u4E86\u786E\u4FDD\u7EBF\u7A0B\u5B89\u5168\u4F1A\u5728\u5199\u5165\u5230\u6587\u4EF6\uFF08\u8FD9\u91CC\u662F\u5199\u5165\u5230\u6807\u51C6\u8F93\u51FA\u8FD9\u4E00\u6587\u4EF6\u63CF\u8FF0\u7B26\uFF09\u65F6\u7ED9\u6587\u4EF6\u52A0\u4E00\u4E2A\u9501\uFF0C\u4F46\u662F\u6CE8\u610F\uFF1A\u8FD9\u4E2A <code>shell</code> \u7A0B\u5E8F\u5728\u4E3B\u4F53\u63A7\u5236\u6D41\u4E2D\u4E5F\u6709 <code>printf</code> \u51FD\u6570\u7684\u8C03\u7528\uFF08\u4F8B\u5982\u6253\u5370\u8FDB\u7A0B\u7684\u63D0\u793A\u6D88\u606F\uFF09\uFF0C\u8003\u8651\u73B0\u5728\u53D1\u751F\u4E86\u8FD9\u6837\u7684\u4E00\u4E2A\u8C03\u7528\uFF0C\u5E76\u4E14\u5728\u4ECE\u6253\u5370\u63D0\u793A\u6D88\u606F\u5230\u7ED9\u6587\u4EF6\u63CF\u8FF0\u7B26\u89E3\u9501\u7684\u8FC7\u7A0B\u4E2D\uFF0C\u6070\u597D\u7A0B\u5E8F\u6536\u5230\u4E00\u4E2A\u7EC8\u6B62\u4FE1\u53F7\uFF0C\u4E8E\u662F\u4FE1\u53F7\u5904\u7406\u51FD\u6570\u88AB\u8C03\u7528\uFF0C\u8FDB\u7A0B\u4F1A\u963B\u585E\u5728\u7ED9\u6587\u4EF6\u63CF\u8FF0\u7B26\u89E3\u9501\u4E4B\u524D\uFF0C\u8F6C\u800C\u53BB\u6267\u884C\u4FE1\u53F7\u5904\u7406\u51FD\u6570\u4E2D\u7684 <code>printf</code> \uFF0C\u800C\u8FD9\u6B21\u7684\u8C03\u7528\u5728\u6267\u884C\u5230\u51C6\u5907\u6253\u5370\u65F6\uFF0C\u5374\u4F1A\u53D1\u73B0\u6807\u51C6\u8F93\u51FA\u88AB\u52A0\u9501\u4E86\uFF08\u56E0\u4E3A\u8FD8\u6CA1\u80FD\u6210\u529F\u89E3\u9501\uFF09\uFF0C\u6545\u4F1A\u505C\u4E0B\u6765\u7B49\u5019\u3002\u4F46\u4FE1\u53F7\u5904\u7406\u51FD\u6570\u5DF2\u7ECF\u963B\u585E\u4E86\u8FDB\u7A0B\u6267\u884C\u6B63\u5E38\u63A7\u5236\u6D41\uFF0C\u81EA\u7136\u4E5F\u5C31\u4E00\u76F4\u7B49\u4E0D\u5230\u8C01\u80FD\u7ED9\u6807\u51C6\u8F93\u51FA\u89E3\u9501\u4E86\uFF1A\u8FD9\u5C31\u9020\u6210\u4E86\u7A0B\u5E8F\u7684\u6B7B\u9501</p><p>\u4E25\u683C\u6765\u8BF4\uFF0C\u6211\u4EEC\u8FD9\u4E2A \u201Ctoy shell\u201D \u76EE\u524D\u8FD8\u662F\u4E00\u4E2A\u975E\u5E38\u4E0D\u5065\u58EE\u7684\u72B6\u6001\u3002\u8FD9\u79CD\u7C7B\u4F3C\u7684\u4FE1\u53F7\u5904\u7406\u66F4\u5408\u7406\u4E5F\u66F4\u666E\u904D\u7684\u65B9\u5F0F\u662F\u4F7F\u7528\u7BA1\u9053\u6765\u5B8C\u6210\uFF0C\u4E0D\u8FC7\u8FD9\u5C31\u5927\u5927\u8D85\u51FA\u4E86\u672C\u5B9E\u9A8C\u7684\u8303\u7574\uFF0C\u6545\u4E0D\u5728\u6B64\u4ECB\u7ECD</p><p>\u81F3\u6B64\uFF0CShell Lab \u7684\u5B9E\u9A8C\u5706\u6EE1\u7ED3\u675F</p>`,67),l=[u],f={setup(i,{expose:n}){return n({frontmatter:{}}),(r,d)=>(s(),a("div",e,l))}};export{f as default};
